const settingsArr = $input.first().json;
const settings = Array.isArray(settingsArr) ? settingsArr[0] : settingsArr;
const n = settings?.ideas_per_day || 5;
const sector = settings?.sector || 'formacion_empresarial_B2B';
const brandKeywords = (settings?.brand_keywords || ['formacion','aprendizaje']).join(', ');
const authorName = settings?.author_name || 'el consultor';
const today = new Date().toLocaleDateString('es-ES', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' });
const year = new Date().getFullYear();

const systemPrompt = "Eres un estratega de contenido para LinkedIn especializado en formacion empresarial B2B en Espana.
Tu tarea: generar " + n + " ideas originales de publicaciones LinkedIn para hoy (" + today + ").

SECTOR: " + sector + "
AUTOR: " + authorName + "
PALABRAS CLAVE: " + brandKeywords + "

Para cada idea devuelve:
- title: Titulo corto de la idea (max 80 chars)
- description: Descripcion de que trataria (150-200 palabras)
- angle: problema | solucion | historia | dato | debate | lista
- suggested_hashtags: Array de 5 strings SIN # (hashtags relevantes)
- trend_source: Que tendencia o contexto justifica esta idea hoy

TENDENCIAS " + year + " A CONSIDERAR:
- IA en formacion y evaluacion del aprendizaje
- Microlearning vs formacion intensiva -- ROI medible
- Formacion de mandos intermedios post-pandemia
- Gamificacion en entornos B2B
- Skills gap en transformacion digital de equipos
- Diversidad generacional en empresas (Gen Z + Millennials + Boomers)
- Bienestar y salud mental en el trabajo como ventaja competitiva
- Upskilling obligatorio en sectores regulados (sanidad, banca, industria)

RESPONDE SOLO JSON: {"ideas":[{"title":"...","description":"...","angle":"...","suggested_hashtags":["..."],"trend_source":"..."}]}";

return [{
  json: {
    system_prompt: systemPrompt,
    user_prompt: "Genera " + n + " ideas de posts LinkedIn para hoy. Que sean variadas en angulo y genuinamente utiles para el sector de formacion B2B en Espana. Nada generico.",
    n_ideas: n
  }
}];

const openaiResponse = $input.first().json;
let ideas = [];
try {
  const content = openaiResponse.choices[0].message.content;
  const parsed = JSON.parse(content);
  ideas = parsed.ideas || [];
} catch(e) {
  throw new Error('Error parsing OpenAI response: ' + e.message);
}

const today = new Date().toISOString().split('T')[0];

const rows = ideas.map(idea => ({
  title: idea.title || 'Sin titulo',
  description: idea.description || '',
  angle: idea.angle || 'idea',
  suggested_hashtags: idea.suggested_hashtags || [],
  trend_source: idea.trend_source || '',
  date_generated: today,
  status: 'new'
}));

return rows.map(row => ({ json: row }));

